import type { RefObject } from 'react';
import { useEffect, useCallback } from 'react';
import { elementsContains } from '../utils/ui';

function useClickOutsideEffect(elementRefs: RefObject<HTMLElement>[], condition: boolean, callback: () => void) {
  const closeOnClickOutside = useCallback(
    ({ target }: MouseEvent) => {
      if (condition) {
        if (
          !elementsContains(
            elementRefs.map(e => e.current),
            target as HTMLElement,
          )
        ) {
          callback();
        }
      }
    },
    [elementRefs, condition, callback],
  );

  useEffect(() => {
    window.addEventListener('mouseup', closeOnClickOutside);
    return () => {
      window.removeEventListener('mouseup', closeOnClickOutside);
    };
  }, [closeOnClickOutside]);
}

export default useClickOutsideEffect;
